<template><PageHeader title="幼儿内容库"><el-button type="primary" @click="add">新增内容</el-button></PageHeader><div class="panel"><el-table :data="rows"><el-table-column prop="type" label="类型"/><el-table-column prop="category" label="分类"/><el-table-column prop="title" label="标题"/><el-table-column prop="auditStatus" label="审核"/><el-table-column label="操作"><template #default="s"><el-button @click="edit(s.row)">编辑</el-button><el-button type="danger" @click="remove(s.row.id)">删除</el-button></template></el-table-column></el-table></div></template><script setup lang="ts">import{onMounted,ref}from'vue';import PageHeader from'@/components/PageHeader.vue';import{adminApi}from'@/services/admin-api';const rows=ref<any[]>([]);async function load(){rows.value=await adminApi.content()}async function add(){await adminApi.addContent({type:'story',category:'原创成长',title:`新故事${Date.now()}`,text:'内容',enabled:true});await load()}async function edit(x:any){await adminApi.updateContent(x.id,{...x,title:`${x.title}（已更新）`});await load()}async function remove(id:string){await adminApi.deleteContent(id);await load()}onMounted(load);</script>
